import { useState } from "react";
import galleryData from "../data/galleryData";
import FlechaAbajo from "../icons/flecha-abajo.svg"; // tu icono

const MasonryGrid = () => {

  const [expandido, setExpandido] = useState(false);

  const imagenesIniciales = galleryData.slice(0, 6);
  const imagenesMostrar = expandido ? galleryData : imagenesIniciales;

  return (
    <div className="flex flex-col items-center">

      {/* GRID */}
      <div
        className={`
          columns-2 md:columns-3 gap-4 space-y-4
          transition-all duration-500 overflow-hidden
          ${expandido ? "max-h-[2000px]" : "max-h-[500px]"}
        `}
      >
        {imagenesMostrar.map((img) => (
          <img
            key={img.id}
            src={img.src}
            alt={img.alt}
            className="w-full rounded-xl break-inside-avoid shadow-md hover:scale-[1.02] transition cursor-pointer"
          />
        ))}
      </div>

      {/* BOTON */}
      {!expandido && (
        <button
          onClick={() => setExpandido(true)}
          className="mt-6 hover:scale-110 transition"
        >
          <img src={FlechaAbajo} className="w-10 opacity-80" />
        </button>
      )}

    </div>
  );
};

export default MasonryGrid;
